 18â†’ */
 19â†’public class TypeArgumentListSpacingRule :
 20â†’    StandardRule("type-argument-list-spacing"),
 21â†’    Rule.Experimental {
 22â†’    override fun beforeVisitChildNodes(
 23â†’        node: ASTNode,
 24â†’        autoCorrect: Boolean,
 25â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 26â†’    ) {
 27â†’        when (node.elementType) {
 28â†’            ElementType.TYPE_ARGUMENT_LIST -> {
 29â†’                visitFunctionDeclaration(node, autoCorrect, emit)
 30â†’                visitInsideTypeArgumentList(node, autoCorrect, emit)
 31â†’            }
 32â†’            ElementType.SUPER_TYPE_LIST, ElementType.SUPER_EXPRESSION ->
 33â†’                visitInsideTypeArgumentList(node, autoCorrect, emit)
 34â†’        }
 35â†’    }
 36â†’
 37â†’    private fun visitFunctionDeclaration(
 38â†’        node: ASTNode,
 39â†’        autoCorrect: Boolean,
 40â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 41â†’    ) {
 42â†’        // No whitespace expected before type argument list of function call
 43â†’        //    val list = listOf <String>()
 44â†’        node
 45â†’            .prevLeaf(includeEmpty = true)
 46â†’            ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 47â†’            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 48â†’
 49â†’        // No whitespace expected after type argument list of function call
 50â†’        //    val list = listOf<String> ()
 51â†’        node
 52â†’            .takeUnless {
 53â†’                // unless it is part of a type reference:
 54â†’                //    fun foo(): List<Foo> { ... }
 55â†’                //    var bar: List<Bar> = emptyList()
 56â†’                it.isPartOfCompositeElementOfType(ElementType.TYPE_REFERENCE)
 57â†’            }
 58â†’            ?.takeUnless {
 59â†’                // unless it is part of a call expression followed by lambda:
 60â†’                //    bar<Foo> { ... }
 61â†’                it.isPartOfCallExpressionFollowedByLambda()
 62â†’            }
 63â†’            ?.lastChildNode
 64â†’            ?.nextLeaf(includeEmpty = true)
 65â†’            ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 66â†’            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 67â†’    }
